# JavaScript Debounce 函数

## 核心实现

```javascript
/**
 * 创建一个防抖函数
 * @param {Function} fn - 要执行的函数
 * @param {number} delay - 延迟时间（毫秒）
 * @param {Object} [options] - 可选配置
 * @param {boolean} [options.leading=false] - 是否在延迟开始前立即执行一次
 * @param {boolean} [options.trailing=true] - 是否在延迟结束后执行（即标准的防抖行为）
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;
  let timer = null;
  let lastArgs = null;
  let lastThis = null;
  let isInvoked = false; // leading 触发标记

  const later = function() {
    timer = null;
    if (trailing && !leading) {
      // 标准 trailing 模式：执行最后一次调用
      fn.apply(lastThis, lastArgs);
      lastArgs = null;
      lastThis = null;
    } else if (trailing && leading && !isInvoked) {
      // leading+trailing 时，leading 已执行过，trailing 不再重复执行
      lastArgs = null;
      lastThis = null;
    } else if (trailing && leading && isInvoked) {
      fn.apply(lastThis, lastArgs);
      lastArgs = null;
      lastThis = null;
      isInvoked = false;
    }
    // 清理引用
    lastArgs = null;
    lastThis = null;
  };

  const debounced = function(...args) {
    lastArgs = args;
    lastThis = this;

    if (timer) {
      clearTimeout(timer);
    }

    // leading 模式：立即执行一次
    if (leading && !timer) {
      isInvoked = true;
      fn.apply(lastThis, lastArgs);
      lastArgs = null;
      lastThis = null;
    }

    timer = setTimeout(later, delay);
  };

  /**
   * 取消未执行的防抖调用
   */
  debounced.cancel = function() {
    if (timer) {
      clearTimeout(timer);
    }
    timer = null;
    lastArgs = null;
    lastThis = null;
    isInvoked = false;
  };

  /**
   * 立即执行并清空定时器
   */
  debounced.flush = function() {
    if (timer) {
      fn.apply(lastThis, lastArgs);
      clearTimeout(timer);
      timer = null;
      lastArgs = null;
      lastThis = null;
      isInvoked = false;
    }
  };

  return debounced;
}
```

---

## 简洁版（最常用）

```javascript
// trailing 防抖（默认行为）：连续触发后，等待 delay 毫秒无新触发，才执行
function debounce(fn, delay) {
  let timer = null;
  return function(...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}
```

```javascript
// leading 防抖：立即执行第一次，然后 delay 内不再响应
function debounceLeading(fn, delay) {
  let timer = null;
  return function(...args) {
    if (!timer) fn.apply(this, args);
    clearTimeout(timer);
    timer = setTimeout(() => { timer = null; }, delay);
  };
}
```

---

## 使用示例

```javascript
// 1. 搜索框输入防抖
const searchInput = document.querySelector('#search');
const handleSearch = debounce((event) => {
  console.log('发起搜索请求:', event.target.value);
  // fetch('/api/search?q=' + event.target.value)
}, 300);

searchInput.addEventListener('input', handleSearch);


// 2. 窗口 resize 防抖
const handleResize = debounce(() => {
  console.log('窗口大小已稳定，执行重排计算');
}, 200);

window.addEventListener('resize', handleResize);


// 3. leading + trailing（例如提交按钮防抖）
const handleSubmit = debounce(
  () => console.log('提交表单'),
  1000,
  { leading: true, trailing: false }
);
// 第一次点击立即提交，1秒内的后续点击被忽略


// 4. 取消与立即执行
const save = debounce(() => console.log('保存中...'), 5000);

// 用户触发了保存
save();

// 用户又做了一些操作，需要取消之前的保存
save.cancel();

// 或者需要立即保存
save.flush();
```

---

## 防抖 vs 节流（Throttle）对比

| 特性 | Debounce（防抖） | Throttle（节流） |
|------|----------------|----------------|
| 执行时机 | 停止触发后执行 | 固定频率执行 |
| 典型场景 | 搜索框输入、窗口 resize | 滚动事件、点击防刷 |
| 效果 | 只认最后一次 | 定期执行一次 |

**一句话记忆**：防抖是"等你消停了再干"，节流是"不管多急，按节奏干"。

---

